FormPage.Stylesheet:
#resultTerminal {
  width: 100%;
  height: 100%;
  padding: 4px 8px;
  box-sizing: border-box;
  /* Match the ISE terminal's minimal scrollbar: transparent track
     with a subtle translucent thumb. Scrollbars Module Level 1
     properties are supported in every modern browser. */
  scrollbar-color: rgba(255, 255, 255, 0.3) transparent;
}
/* Let the colour CodeBeside pushes onto #resultTerminal (from the
   session's ForegroundColor / BackgroundColor settings, or the fc/bc
   query params) win over jquery.terminal's default black/white. */
#resultTerminal.terminal,
#resultTerminal .terminal-output,
#resultTerminal .terminal-output > div,
#resultTerminal .terminal-output > div > div {
  background-color: inherit !important;
  color: inherit !important;
}
#resultTerminal .cmd, #resultTerminal .cmd-prompt, #resultTerminal .cmd-cursor {
  display: none !important;
}

FormPage.Script:
window.speResultViewerInit = function() {
  var run = function() {
    var raw = (typeof window.resultPayload === 'string') ? window.resultPayload : '';
    var t = $viewer('#resultTerminal').terminal(function() {}, {
      greetings: false,
      prompt: '',
      exit: false,
      clear: false,
      name: 'resultViewer',
      scrollOnEcho: true
    });
    t.pause();
    if (raw.length > 0) { t.echo(raw); }
  };
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', run);
  } else {
    run();
  }
};
